use std::collections::{HashMap, VecDeque};

fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n == 0 {
        return 0;
    }
    let max_num = 1_000_000;
    // Precompute sieve of Eratosthenes
    let mut sieve = vec![true; (max_num + 1) as usize];
    sieve[0] = false;
    sieve[1] = false;
    for i in 2..=max_num {
        if sieve[i] {
            let mut j = i * i;
            while j <= max_num {
                sieve[j as usize] = false;
                j += i;
            }
        }
    }
    // Precompute smallest prime factors (SPF)
    let mut spf = vec![0; (max_num + 1) as usize];
    for i in 2..=max_num {
        if spf[i] == 0 {
            spf[i] = i;
            let mut j = i * 2;
            while j <= max_num {
                if spf[j] == 0 {
                    spf[j] = i;
                }
                j += i;
            }
        }
    }
    // Preprocess prime indices
    let mut prime_indices = HashMap::new();
    for (j, &num) in nums.iter().enumerate() {
        if num == 1 {
            continue;
        }
        let mut x = num;
        let mut factors = std::collections::HashSet::new();
        while x > 1 {
            let p = spf[x as usize];
            factors.insert(p);
            while x % p == 0 {
                x /= p;
            }
        }
        for p in factors {
            prime_indices.entry(p).or_insert_with(Vec::new).push(j);
        }
    }
    // BFS
    let mut visited = vec![-1; n];
    let mut queue = VecDeque::new();
    queue.push_back(0);
    visited[0] = 0;
    while let Some(current) = queue.pop_front() {
        if current == n - 1 {
            return visited[current] as i64;
        }
        // Check adjacent indices
        let neighbors = [current - 1, current + 1];
        for &neighbor in &neighbors {
            if neighbor >= 0 && neighbor < n && visited[neighbor] == -1 {
                visited[neighbor] = visited[current] + 1;
                queue.push_back(neighbor);
            }
        }
        // Check teleportation if current is a prime
        if sieve[nums[current] as usize] {
            let p = nums[current];
            if let Some(indices) = prime_indices.get(&p) {
                for &j in indices {
                    if j != current && visited[j] == -1 {
                        visited[j] = visited[current] + 1;
                        queue.push_back(j);
                    }
                }
            }
        }
    }
    -1
}
