    sieve[0] = false;
    sieve[1] = false;
    for i in 2..=max_num {
        if sieve[i] {
            for j in (i * i)..=max_num {
                if j % i == 0 {
                    sieve[j] = false;
                }
            }
        }
    }
    let mut spf = vec![0; max_num + 1];
    for i in 2..=max_num {
        if spf[i] == 0 {
            spf[i] = i;
            for j in (i * 2)..=max_num {
                if j % i == 0 {
                    if spf[j] == 0 {
                        spf[j] = i;
                    }
                }
            }
        }
    }
    let mut prime_indices = HashMap::new();
    for (j, &num) in nums.iter().enumerate() {
        if num == 1 {
            continue;
        }
        let mut x = num;
        let mut factors = std::collections::HashSet::new();
        while x > 1 {
            let p = spf[x];
            factors.insert(p);
            while x % p == 0 {
                x /= p;
